import './Post.css'
import React, { Component } from 'react'
import { Link } from 'react-router-dom';
import { deleteNews } from '../../db.js'

export default class Post extends Component {
    constructor(props) {
        super(props)
    
        this.state = {
            actBtn: false
        }
    }
    
    render() {
        const { img, id, title, tags } = this.props.list

        return (
            <Link to={`/posts/${id}`} className="card-post n-s" id={id} onMouseMove={()=>{this.setState({actBtn:true})}} onMouseOut={()=>{this.setState({actBtn:false})}}>
                <div className={this.state.actBtn ? "tags-block" : "d-none"}>{tags}</div>
                {this.props.x ? <div className={this.state.actBtn ? "x-class" : "d-none"} onClick={()=>{
                    let idComp = `num${id}` 
                    deleteNews(idComp)
                }}>Удалить</div> : <div></div>}
                {id}
                <img className="img-post" width="100%" src={img} alt={`title: ${title}`} />
            </Link >
        )
    }
}
